To resolve this issue, we need to handle the `404 Not Found` error gracefully by treating it as a successful deletion (since the resource is already gone) and then making sure we remove those successfully deleted (or already missing) instances from the local `.state` file. 

Additionally, by loading the `.state` file we can make the `destroy` command much more robust: it can also clean up instances that might still exist in the state file but were removed from the `maglev.yaml` configuration (orphaned nodes).

Here is the updated `src/command/destroy.rs` file:

```rust
// src/command/destroy.rs

use crate::provider::load_provider;
use crate::state::State;
use crate::utils::prompt_yes_no;

// ---------------------------------------------------------------------------
// `destroy` subcommand
// ---------------------------------------------------------------------------

pub fn destroy_config(config_path: &str) -> Result<(), Box<dyn std::error::Error>> {
    println!("=== Maglev Destroy ===\n");
    println!("Reading config: {config_path}");

    let loaded = load_provider(config_path)?;
    let common = loaded.common();
    let mut state = State::load(config_path);

    println!("\n── Provider settings ────────────────────────────────────────────────────");
    loaded.describe();

    println!("\n── Instances to destroy ─────────────────────────────────────────────────");

    let mut all_nodes: Vec<(String, String, String)> = Vec::new(); // (group_name, group_type, node)
    let mut seen_nodes = std::collections::HashSet::new();

    for group in &common.groups {
        for node in &group.node {
            println!("  [{}] {}  →  {}", group.group_type, group.name, node);
            all_nodes.push((group.name.clone(), group.group_type.clone(), node.clone()));
            seen_nodes.insert(node.clone());
        }
    }

    // Also include any nodes present in the state file that are no longer in the config
    for node in state.instances.keys() {
        if !seen_nodes.contains(node) {
            println!("  [state] orphaned  →  {}", node);
            all_nodes.push(("orphaned".to_string(), "state".to_string(), node.clone()));
        }
    }

    let total = all_nodes.len();
    if total == 0 {
        println!("\nNo instances found in configuration or state to destroy.");
        return Ok(());
    }

    println!();
    println!("⚠  This action is IRREVERSIBLE. All {total} VM instance(s) and their boot");
    println!("   disks will be permanently deleted.");

    if !prompt_yes_no("\nProceed with destroying all VM instances?") {
        println!("Aborted — nothing was deleted.");
        return Ok(());
    }

    let provider = loaded.provider();

    for (group_name, group_type, node) in &all_nodes {
        match provider.destroy_vm(node) {
            Ok(_) => {
                println!("\n[{group_type}/{group_name}] {node} deleted");
                state.instances.remove(node);
            }
            Err(e) => {
                // If it's already deleted/missing on the cloud provider, treat it as a success 
                // and purge it from our local state tracking.
                if e.to_string().contains("404") {
                    println!("\n[{group_type}/{group_name}] {node} not found (already deleted)");
                    state.instances.remove(node);
                } else {
                    eprintln!("  ✗ Failed to delete {node}: {e}");
                }
            }
        }
    }

    // Save updated state (removing destroyed instances)
    if let Err(e) = state.save(config_path) {
        eprintln!("\n⚠ Failed to save state file updates: {e}");
    }

    println!("\n✓ Deletion requests processed. Operations may take a minute to complete.");
    Ok(())
}
